/// The unit display pattern for a CLDR locale key, unit, style and plural category.
pub fn unit_pattern(loc: &str, unit: &str, style: &str, plural: &str) -> Option<&'static str> {
    UNIT_PATTERNS
        .iter()
        .find(|(l, u, s, p, _)| *l == loc && *u == unit && *s == style && *p == plural)
        .map(|(_, _, _, _, pat)| *pat)
}
